SELECT COUNT(*) 
FROM problem_tags
WHERE tag_name = 'matrix';

SELECT user_id, problem_id
FROM user_performance
WHERE score >= 90;

SELECT AVG(runtime) AS average_runtime
FROM attempts
WHERE user_id = 0;

SELECT runtime
FROM attempts
WHERE problem_id = 1 AND status = 'accepted';

SELECT difficulty_name
FROM difficulty_levels
WHERE difficulty_id = 0;

SELECT content, upvotes
  FROM discussions
  WHERE upvotes = (SELECT MAX(upvotes) FROM discussions);

SELECT COUNT(*) AS total_attempts, AVG(runtime) AS average_runtime
FROM attempts
WHERE problem_id = 1;

SELECT AVG(score) AS average_score
FROM user_performance
WHERE user_id = 0;
